  1	import React, {
  2	  ChangeEvent,
  3	  DetailedHTMLProps,
  4	  FC,
  5	  HTMLAttributes,
  6	  memo,
  7	  useMemo,
  8	  useState,
  9	} from 'react';
 10	import TagsInput from 'react-tagsinput';
 11	
 12	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
 13	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 14	import { isEmpty } from '@kubevirt-utils/utils/utils';
 15	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
 16	import { Label as PFLabel, Stack, StackItem, Truncate } from '@patternfly/react-core';
 17	
 18	import { isLabelValid, labelsArrayToObject, labelsToArray } from './utils';
 19	
 20	import './LabelsModal.scss';
 21	
 22	type LabelsModalProps = {
 23	  initialLabels?: {
 24	    [key: string]: string;
 25	  };
 26	  isOpen: boolean;
 27	  labelClassName?: string;
 28	  modalDescriptionText?: string;
 29	  obj: K8sResourceCommon;
 30	  onClose: () => void;
 31	  onLabelsSubmit: (labels: { [key: string]: string }) => Promise<K8sResourceCommon | void>;
 32	};
 33	
 34	export const LabelsModal: FC<LabelsModalProps> = memo(
 35	  ({
 36	    initialLabels,
 37	    isOpen,
 38	    labelClassName,
 39	    modalDescriptionText,
 40	    obj,
 41	    onClose,
 42	    onLabelsSubmit,
 43	  }) => {
 44	    const { t } = useKubevirtTranslation();
 45	    const [inputValue, setInputValue] = useState('');
 46	    const [isInputValid, setIsInputValid] = useState(true);
 47	
 48	    const initLabels = useMemo(() => {
 49	      if (!isEmpty(initialLabels)) return initialLabels;
 50	      if (!isEmpty(obj?.metadata?.labels)) return obj?.metadata?.labels;
 51	      return {};
 52	    }, [initialLabels, obj?.metadata?.labels]);
 53	    const [labels, setLabels] = useState<string[]>(labelsToArray(initLabels));
 54	
 55	    const onInputChange = (e: ChangeEvent<HTMLInputElement>) => {
 56	      const value = e.target.value;
 57	
 58	      if (value === '') {
 59	        setInputValue(value);
 60	        setIsInputValid(true);
 61	        return;
 62	      }
 63	      setInputValue(value);
 64	      setIsInputValid(isLabelValid(value));
 65	    };
 66	
 67	    const handleLabelsChange = (newLabels: string[], changed: string[]) => {
 68	      const newLabel = changed[0];
 69	      if (!isLabelValid(newLabel)) {
 70	        setIsInputValid(false);
 71	        return;
 72	      }
 73	
 74	      // duplicate labels
 75	      if (newLabels.filter((l) => l === newLabel).length > 1) {
 76	        setIsInputValid(false);
 77	        return;
 78	      }
 79	
 80	      // if key exists, overwrite value
 81	      if (newLabels.filter((l) => l.split('=')[0] === newLabel.split('=')[0]).length > 1) {
 82	        const filteredLabels = newLabels.filter((l) => l.split('=')[0] !== newLabel.split('=')[0]);
 83	        setLabels([...filteredLabels, newLabel]);
 84	        setInputValue('');
 85	        return;
 86	      }
 87	
 88	      setLabels(newLabels);
 89	      setInputValue('');
 90	    };
 91	
 92	    const renderTag = ({ getTagDisplayValue, key, onRemove, tag }) => {
 93	      return (
 94	        <PFLabel
 95	          className={'co-label tag-item-content'.concat(labelClassName || '')}
 96	          key={key}
 97	          onClose={() => onRemove(key)}
 98	        >
 99	          <Truncate content={getTagDisplayValue(tag)} />
100	        </PFLabel>
101	      );
102	    };
103	
104	    const inputProps = {
105	      autoFocus: true,
106	      className: 'input'.concat(isInputValid ? '' : ' invalid-tag'),
107	      ['data-test']: 'tags-input',
108	      id: 'tags-input',
109	      onChange: onInputChange,
110	      placeholder: labels.length === 0 ? 'app=frontend' : '',
111	      spellCheck: 'false',
112	      value: inputValue,
113	    };
114	
115	    // Keys that add tags: Enter
116	    const addKeys = [13];
117	    // Backspace deletes tags, but not if there is text being edited in the input field
118	    const removeKeys = inputValue.length ? [] : [8];
119	
120	    return (
121	      <TabModal
122	        headerText={t('Edit labels')}
123	        isOpen={isOpen}
124	        obj={obj}
125	        onClose={onClose}
126	        onSubmit={() => onLabelsSubmit(labelsArrayToObject(labels))}
127	      >
128	        <Stack hasGutter>
129	          <StackItem>
130	            {modalDescriptionText ??
131	              t(
132	                'Labels help you organize and select resources. Adding labels below will let you query for objects that have similar, overlapping or dissimilar labels.',
133	              )}
134	          </StackItem>
135	          <StackItem>
136	            <div className="kv-labels-modal-body">
137	              <tags-input>
138	                <TagsInput
139	                  addKeys={addKeys}
140	                  addOnBlur
141	                  className="tags"
142	                  inputProps={inputProps}
143	                  onChange={handleLabelsChange}
144	                  removeKeys={removeKeys}
145	                  renderTag={renderTag}
146	                  value={labels}
147	                />
148	              </tags-input>
149	            </div>
150	          </StackItem>
151	        </Stack>
152	      </TabModal>
153	    );
154	  },
155	);
156	
157	// console is declaring a new html element for some reason, we have to copy it for css reasons.
158	declare global {
159	  // eslint-disable-next-line @typescript-eslint/no-namespace
160	  namespace JSX {
161	    interface IntrinsicElements {
162	      'tags-input': DetailedHTMLProps<HTMLAttributes<HTMLElement>, HTMLElement>;
163	    }
164	  }
165	}

